async function buildWeekly(){const q=new URLSearchParams(formData(document.getElementById('weeklyForm')));try{const r=await request('/api/weekly-report?'+q);const labels={work_logs:'Логи работ',receipts:'Приходы',received_quantity:'Принято',issues:'Расходы',issued_quantity:'Списано',cable_received:'Кабеля принято',cable_issued:'Кабеля списано',problem_rows:'Проблемные строки',loaded_deliveries:'Загруженные поставки',accepted_delivery_items:'Принятые позиции поставок',delivery_problem_rows:'Проблемные строки поставок'};document.getElementById('weeklyCards').innerHTML=Object.entries(r.summary).map(([k,v])=>`<div class="card"><span>${labels[k]}</span><strong>${Number(v).toLocaleString('ru-RU')}</strong></div>`).join('');const render=(id,rows)=>document.getElementById(id).innerHTML=rows.map(x=>`<tr><td>${esc(x.name)}</td><td>${Number(x.received).toLocaleString('ru-RU')}</td><td>${Number(x.issued).toLocaleString('ru-RU')}</td></tr>`).join('')||'<tr><td class="empty" colspan="3">Нет данных</td></tr>';render('weeklyProjects',r.projects);render('weeklyTypes',r.types)}catch(e){notify(e.message,true)}}document.getElementById('weeklyForm').onsubmit=e=>{e.preventDefault();buildWeekly()};document.getElementById('downloadWeekly').onclick=()=>{const f=document.getElementById('weeklyForm');if(f.reportValidity())location.href='/export/weekly-report.csv?'+new URLSearchParams(formData(f))};
